const items = $input.all();

// Extract all rows
const data = items.map(item => item.json);

// Total calculations
const total_confirmed = data.reduce((sum, row) => sum + Number(row.confirmed || 0), 0);
const total_deaths = data.reduce((sum, row) => sum + Number(row.deaths || 0), 0);
const total_recovered = data.reduce((sum, row) => sum + Number(row.cured || 0), 0);

// Active = confirmed - recovered - deaths
const active_cases = total_confirmed - total_recovered - total_deaths;

// Latest date (for new cases)
const latestDate = data[data.length - 1]?.date;

// Filter latest day data
const latestData = data.filter(row => row.date === latestDate);

// New cases today
const new_cases_today = latestData.reduce((sum, row) => sum + Number(row.confirmed || 0), 0);

// Recovery rate
const recovery_rate = ((total_recovered / total_confirmed) * 100).toFixed(2);

// CFR
const cfr = ((total_deaths / total_confirmed) * 100).toFixed(2);

// Final output
return [{
  json: {
    report_date: new Date().toLocaleDateString('en-IN'),
    case_metrics: {
      total_confirmed,
      total_deaths,
      total_recovered,
      active_cases,
      new_cases_today,
      recovery_rate,
      cfr
    }
  }
}];

